import "./EmployeeDetails.css";
import { useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import { isAdmin, isEmployee, getLoggedInUser } from "../auth";

function EmployeeDetails() {
  const navigate = useNavigate();
  const [employees, setEmployees] = useState([]);

  const user = getLoggedInUser();

  useEffect(() => {
    const storedEmployees =
      JSON.parse(localStorage.getItem("employees")) || [];
    setEmployees(storedEmployees);
  }, []);

  // -------- SUPER SAFE FILTER --------
  const filteredEmployees = isEmployee()
    ? employees.filter(
        (emp) =>
          String(emp.empId) === String(user?.empId) ||
          String(emp.id) === String(user?.empId) ||
          String(emp.email) === String(user?.username)
      )
    : employees;

  // -------- SAFE NAME --------
  const getEmployeeName = (emp) => {
    const first = emp.firstName?.trim() || "";
    const last = emp.lastName?.trim() || "";
    if (first || last) return `${first} ${last}`.trim();
    if (emp.name) return emp.name;
    return "Unnamed";
  };

  // -------- DELETE EMPLOYEE --------
  const handleDelete = (empId) => {
    if (!window.confirm("Are you sure you want to delete this employee?"))
      return;

    let allEmployees = JSON.parse(localStorage.getItem("employees")) || [];
    allEmployees = allEmployees.filter(
      (e) =>
        String(e.id) !== String(empId) &&
        String(e.empId) !== String(empId)
    );

    localStorage.setItem("employees", JSON.stringify(allEmployees));
    setEmployees(allEmployees);

    let salary = JSON.parse(localStorage.getItem("salaryHistory")) || [];
    salary = salary.filter((s) => String(s.empId) !== String(empId));
    localStorage.setItem("salaryHistory", JSON.stringify(salary));

    alert("Employee deleted successfully!");
  };

  return (
    <div className="employee-page">
      <h2 className="employee-title">Manage Employees</h2>

      <div className="employee-actions">
        <input
          type="text"
          placeholder="Search By Employee ID"
          className="search-box"
        />

        {isAdmin() && (
          <button
            className="add-btn"
            onClick={() => navigate("/dashboard/employee-details/add")}
          >
            Add New Employee
          </button>
        )}
      </div>

      <table className="employee-table">
        <thead>
          <tr>
            <th>S No</th>
            <th>Name</th>
            <th>DOB</th>
            <th>Department</th>

            {/* Hide Action column header for Employee */}
            {isAdmin() && <th>Action</th>}
          </tr>
        </thead>

        <tbody>
          {filteredEmployees.length > 0 ? (
            filteredEmployees.map((emp, index) => (
              <tr key={emp.id}>
                <td>{index + 1}</td>

                <td>{getEmployeeName(emp)}</td>
                <td>{emp.dob}</td>
                <td>{emp.department}</td>

                {/* Hide buttons for Employee */}
                {isAdmin() && (
                  <td className="actions">
                    <button
                      className="view"
                      onClick={() =>
                        navigate(`/dashboard/employee-details/view/${emp.id}`)
                      }
                    >
                      View
                    </button>

                    <button
                      className="edit"
                      onClick={() =>
                        navigate(`/dashboard/employee-details/edit/${emp.id}`)
                      }
                    >
                      Edit
                    </button>

                    <button
                      className="salary"
                      onClick={() =>
                        navigate(
                          `/dashboard/employee-details/salary/add/${emp.id}`
                        )
                      }
                    >
                      Salary
                    </button>

                    <button
                      className="delete"
                      onClick={() => handleDelete(emp.id)}
                    >
                      Delete
                    </button>
                  </td>
                )}
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="5" className="no-data">
                No Employees Found
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

export default EmployeeDetails;
